code.C++:
# cook your dish here
t = int(input())
for i in range(t):
    tf = int(input())
    f = list(map(int,input().split(' ')))
    count = 0
    if tf > 1 :
        for i in range(1,tf) :
            if f[i] == f[i-1] :
                count +=1
    print(tf-count)

